-- Clear market match sessions (references contacts)
DELETE FROM market_match_sessions;

-- Clear lender intro log (may reference contacts/transactions)
DELETE FROM lender_intro_log;

-- Clear tasks and task notes referencing contacts
DELETE FROM task_notes WHERE taskId IN (SELECT id FROM tasks WHERE contactId IS NOT NULL);
DELETE FROM tasks WHERE contactId IS NOT NULL;

-- Clear activity log for contacts
DELETE FROM activity_log WHERE contactId IS NOT NULL;

-- Clear approval requests referencing contacts
DELETE FROM approval_requests WHERE contactId IS NOT NULL;

-- Clear feedback referencing contacts
DELETE FROM feedback WHERE contactId IS NOT NULL;

-- Clear documents referencing contacts/transactions
DELETE FROM documents WHERE contactId IS NOT NULL;
DELETE FROM documents WHERE transactionId IS NOT NULL;

-- Now clear transaction child data
DELETE FROM transaction_notes;
DELETE FROM transaction_documents;
DELETE FROM transaction_payout_items;
DELETE FROM commission_exceptions;

-- Clear transactions
DELETE FROM transactions;

-- Clear listing notes and listings
DELETE FROM listing_notes;
DELETE FROM listings;

-- Clear communications, agent connections, smart plan data
DELETE FROM communications;
DELETE FROM agent_connections;
DELETE FROM smart_plan_enrollments;
DELETE FROM smart_plan_executions;

-- Clear contact-property links
DELETE FROM contact_properties;

-- Clear property ownership and properties
DELETE FROM property_ownership;
DELETE FROM properties;

-- Clear contacts
DELETE FROM contacts;

